import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    N = int(input_data[0])

    events = []
    for i in range(N):
        events.append((int(input_data[1 + i]), 1))
    for i in range(N):
        events.append((int(input_data[1 + N + i]), 0))

    events.sort(key=lambda x: (-x[0], x[1]))

    MOD = 10**9 + 7

    DP2 = [[0] * (N + 1) for _ in range(2 * N + 2)]
    DP2[2 * N + 1][0] = 1

    for i in range(2 * N, 0, -1):
        type = events[i - 1][1]
        nxt = DP2[i + 1]
        curr = DP2[i]
        if type == 1:
            curr[1:] = nxt[:-1]
        else:
            for c in range(N):
                curr[c] = (nxt[c] + nxt[c + 1] * (c + 1)) % MOD
            curr[N] = nxt[N] % MOD

    ans = DP2[1][0]

    fact = [1] * (N + 1)
    for i in range(1, N + 1):
        fact[i] = (fact[i - 1] * i) % MOD

    prev_dp1 = [0] * (N + 1)
    prev_dp1[0] = 1

    for i in range(1, 2 * N + 1):
        type = events[i - 1][1]

        if type == 1:
            nxt = DP2[i + 1]
            ways = 0
            for b in range(N + 1):
                if prev_dp1[b] and nxt[b]:
                    ways = (ways + prev_dp1[b] * nxt[b] % MOD * fact[b]) % MOD
            ans = (ans + ways) % MOD

        curr_dp1 = [0] * (N + 1)
        if type == 0:
            curr_dp1[1:] = prev_dp1[:-1]
        else:
            for b in range(N):
                curr_dp1[b] = (prev_dp1[b] + prev_dp1[b + 1] * (b + 1)) % MOD
            curr_dp1[N] = prev_dp1[N] % MOD

        prev_dp1 = curr_dp1

    print(ans)

if __name__ == '__main__':
    solve()
